(function() {
  const allText = document.body.innerText;
  const lines = allText.split('\n');

  let forecastData = {};
  let currentDay = '';
  let dayCount = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // Check if this is a day header
    if (line.match(/^(Sunday|Monday|Tuesday|Wednesday|Thursday|Friday|Saturday) \d+ \w+$/)) {
      if (dayCount < 5) {
        currentDay = line;
        forecastData[currentDay] = [];
        dayCount++;
      } else {
        break;
      }
    } else if (currentDay && dayCount <= 5) {
      forecastData[currentDay].push(line);
    }
  }

  // Format the output
  let output = "WEATHER FORECAST FOR BINDA, NSW\n";
  output += "========================================\n\n";

  for (let day in forecastData) {
    output += day + "\n";
    output += "-".repeat(day.length) + "\n";

    let data = forecastData[day].join('\n');

    // Extract key information
    const rainMatch = data.match(/Chance of any rain\s+.*?(\d+%)/);
    const tempMatches = data.match(/Air temperature \(°C\)\s+.*?(\d+)\s+(\d+)\s+(\d+)\s+(\d+)/);
    const windSpeedMatch = data.match(/Wind speed km\/h\s+knots\s+.*?(\d+)\s+(\d+)\s+(\d+)\s+(\d+)/);
    const windDirMatch = data.match(/Wind direction\s+.*?([A-Z]+)\s+([A-Z]+)\s+([A-Z]+)\s+([A-Z]+)/);

    if (rainMatch) {
      output += "Chance of rain: " + rainMatch[1] + "\n";
    }

    if (tempMatches) {
      output += "Temperatures: " + tempMatches[1] + "°C (2PM), " + tempMatches[2] + "°C (5PM), " + tempMatches[3] + "°C (8PM), " + tempMatches[4] + "°C (11PM)\n";
    }

    if (windSpeedMatch && windDirMatch) {
      output += "Wind: " + windSpeedMatch[1] + " km/h " + windDirMatch[1] + " at 2PM\n";
    }

    output += "\n";
  }

  return output;
})();
